#include <bits/stdc++.h>
using namespace std;
long long b,len,n[4005],m[4005];
int main(){
    string s1,s2;
    cin>>b>>s1>>s2;
    len=max(s1.size(),s2.size());
    for(int i=0;i<s1.size();i++){
        if(s1[s1.size()-i-1]>='A' && s1[s1.size()-i-1]<='Z')
            n[i]=s1[s1.size()-i-1]-'A'+10;
        else n[i]=s1[s1.size()-i-1]-'0';
    }
    for(int i=0;i<s2.size();i++){
        if(s2[s2.size()-i-1]>='A' && s2[s2.size()-i-1]<='Z')
            m[i]=s2[s2.size()-i-1]-'A'+10;
        else m[i]=s2[s2.size()-i-1]-'0';
    }
    for(int i=0;i<len;i++){
        n[i]=n[i]+m[i];
        n[i+1]+=n[i]/b;
        n[i]%=b;
    }
    if(n[len])len++;
    for(int i=0;i<len;i++){
    	/*if(n[len-i-1]>9 && b>10)cout<<char(n[len-i-1]-10+'A');
    	else */cout<<n[len-i-1];
	}
    return 0;
}
